import React, { useState, useEffect } from "react";
import { Link, useNavigate } from "react-router-dom";
import { useApp } from "../../context/AppContext";
import {
  generateDemoSteps,
  generateDemoWater,
  generateDemoWeight,
} from "../../utils/helpers";

export default function RegisterPage() {
  const navigate = useNavigate();
  const { dispatch } = useApp();
  const [form, setForm] = useState({
    name: "",
    email: "",
    password: "",
    height: "",
    weight: "",
    age: "",
    gender: "male",
  });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    console.group("📝 RegisterPage Component");
    /* eslint-disable */console.log(...oo_oo(`3915161076_27_4_27_66_4`,"Component mounted at:", new Date().toISOString()));
    /* eslint-disable */console.log(...oo_oo(`3915161076_28_4_28_44_4`,"Initial form state:", form));
    console.groupEnd();
    return () => {
      /* eslint-disable */console.log(
        ...oo_oo(`3915161076_31_6_34_7_4`,"📝 RegisterPage Component unmounted at:",
        new Date().toISOString()),
      );
    };
  }, []);

  const handleChange = (key, value) => {
    /* eslint-disable */console.log(
      ...oo_oo(`3915161076_39_4_41_5_4`,`📝 Form change: ${key} = ${["password", "email"].includes(key) ? "***" : value}`),
    );
    setForm((prev) => ({ ...prev, [key]: value }));
  };

  const handleSubmit = (event) => {
    event.preventDefault();
    const startTime = performance.now();
    console.group("🚀 Registration Attempt");
    /* eslint-disable */console.log(...oo_oo(`3915161076_49_4_49_55_4`,"Timestamp:", new Date().toISOString()));
    /* eslint-disable */console.log(...oo_oo(`3915161076_50_4_50_65_4`,"Attempting registration for email:", form.email));
    /* eslint-disable */console.log(...oo_oo(`3915161076_51_4_55_6_4`,"Form data:", {
      ...form,
      password: "***",
      email: form.email.replace(/(.{2}).*(@.*)/, "$1***$2"),
    }));

    setError("");

    if (!form.name || !form.email || !form.password) {
      const endTime = performance.now();
      /* eslint-disable */console.error(...oo_tx(`3915161076_61_6_61_76_11`,"❌ Validation failed: missing name, email, or password"));
      /* eslint-disable */console.log(...oo_oo(`3915161076_62_6_62_78_4`,"Validation time:", (endTime - startTime).toFixed(2) + "ms"));
      console.groupEnd();
      setError("Vui long nhap ten, email va mat khau.");
      return;
    }

    if (form.password.length < 6) {
      const endTime = performance.now();
      /* eslint-disable */console.error(...oo_tx(`3915161076_70_6_70_62_11`,"❌ Validation failed: password too short"));
      /* eslint-disable */console.log(...oo_oo(`3915161076_71_6_71_59_4`,"Password length:", form.password.length));
      /* eslint-disable */console.log(...oo_oo(`3915161076_72_6_72_78_4`,"Validation time:", (endTime - startTime).toFixed(2) + "ms"));
      console.groupEnd();
      setError("Mat khau phai co it nhat 6 ky tu.");
      return;
    }

    if (!form.height || !form.weight || !form.age) {
      const endTime = performance.now();
      /* eslint-disable */console.error(...oo_tx(`3915161076_80_6_80_63_11`,"❌ Validation failed: missing health info"));
      /* eslint-disable */console.log(...oo_oo(`3915161076_81_6_85_8_4`,"Health data:", {
        height: form.height,
        weight: form.weight,
        age: form.age,
      }));
      /* eslint-disable */console.log(...oo_oo(`3915161076_86_6_86_78_4`,"Validation time:", (endTime - startTime).toFixed(2) + "ms"));
      console.groupEnd();
      setError("Vui long nhap day du thong tin suc khoe.");
      return;
    }

    try {
      const users = JSON.parse(localStorage.getItem("health_users") || "[]");
